// AnnotationListSidebar.js
import React from 'react';
import './AnnotationListSidebar.css';

export default function AnnotationListSidebar({
  annotations,
  onDeleteAnnotation,
  onUpdateAnnotation,
  labelClasses,
  selectedLabelClass,
  setSelectedLabelClass
}) {
  return (
    <div className="anno-sidebar">
      <h3>Annotations</h3>
      {annotations.length === 0 && <p>No annotations yet.</p>}

      {/* If you still want to show the list of shapes... */}
      {annotations.map((ann, i) => (
        <div key={i} className="anno-item">
          <div>
            <span className="shape-type">{ann.type.toUpperCase()}</span>{' '}
            <span className="shape-label">{ann.label || ''}</span>
          </div>
          <div className="anno-actions">
            {/* We can keep a "Del" button if desired */}
            <button onClick={() => onDeleteAnnotation(i)}>Del</button>
          </div>
        </div>
      ))}

      {/* ---- Here's the single "Active Label" dropdown ---- */}
      <h3 style={{ marginTop: 16 }}>Active Label</h3>
      <select
        value={selectedLabelClass}
        onChange={(e) => setSelectedLabelClass(e.target.value)}
      >
        {labelClasses.map((lc, i) => (
          <option key={i} value={lc.name}>
            {lc.name}
          </option>
        ))}
      </select>
    </div>
  );
}
